import os
import boto3
import requests
from PIL import Image
import io
from flask import Flask, request
from pyv8 import V8

app = Flask(__name__)
s3 = boto3.client('s3')

@app.route('/screenshot', methods=['POST'])
def screenshot():
    url = request.json.get('url')
    if not url:
        return {"error": "Missing URL"}, 400

    v8 = V8()
    v8.execute("""
        var system = require('system');
        var page = require('webkit').createPage();
        page.open(system.args[1], function (status) {
            if (status != 'success') {
                console.log('Unable to access network.');
                return;
            }
            page.render({
                path: system.tempDir + '/screenshot.png',
                format: 'png'
            }, function () {
                sys.exit(0);
            });
        });
    """)

    v8.args = [url]
    v8.run()
    v8.dispatch('page.onInitialized')
    screenshot_path = os.path.join('/tmp', 'screenshot.png')
    with open(screenshot_path, 'rb') as f:
        img_data = f.read()

    s3.upload_fileobj(img_data, 'bucket-name', url.split('/')[-1] + '.png')

    return {"url": url.split('/')[-1] + '.png'}

if __name__ == "__main__":
    app.run()